function: async () => {
  await new Promise(r => setTimeout(r, 6000)); // let the startup gate finish
  document.querySelector('button[data-target="server-management"]').click();
  await new Promise(r => setTimeout(r, 600));
  document.querySelector('#nav-servers [data-server-key="logger-api"]').click();
  await new Promise(r => setTimeout(r, 1500)); // let ServerLogController poll once
  const tab = document.querySelector('#nav-servers [data-server-key="logger-api"]');
  const pill = document.getElementById('srv-status');
  const txt = document.getElementById('srv-status-text');
  const btn = document.getElementById('srv-restart-btn');
  return {
    tabClasses: [...tab.classList].filter(c => c.startsWith('server-')).join(' '),
    pillClasses: pill?.className,
    pillBg: pill ? getComputedStyle(pill).backgroundColor : null,
    statusText: txt?.textContent,
    restartBtn: btn ? btn.textContent + ' (disabled=' + btn.disabled + ')' : 'MISSING',
  };
}

