function: async () => {
  await new Promise(r => setTimeout(r, 6000)); // startup gate
  document.querySelector('button[data-target="model-stats"]').click();
  await new Promise(r => setTimeout(r, 400));
  // click W11 Codex OAuth
  document.querySelector('#nav-model-stats [data-source="w11-codex"]').click();
  await new Promise(r => setTimeout(r, 1500)); // fetch + render + color poll
  const body = document.getElementById('model-stats-body');
  const tabColors = [...document.querySelectorAll('#nav-model-stats [data-source]')].map(t => ({
    src: t.dataset.source,
    cls: [...t.classList].filter(c => c.startsWith('server-')).join(',') || '(none)'
  }));
  const bars = [...body.querySelectorAll('.ms-bar-fill')].map(b => b.style.width + ' / ' + b.style.background);
  return {
    heading: body.querySelector('h3')?.textContent,
    model: body.querySelector('code')?.textContent,
    windowHeads: [...body.querySelectorAll('.ms-window-head')].map(h => h.textContent),
    bars,
    tabColors,
  };
}

